	["EmpowerTapControlsReleaseThreshold"] = { zh = "设置按下再轻点式蓄力法术接受松开或重按操作前的等待毫秒数。", en = "Sets the time in milliseconds after which release/re-hold requests will be registered for press-and-tap empowers. Begins when the cast is sent from the client.", ver = "10.0.0" },
	["EnableBlinkApplicationIcon"] = { zh = "允许游戏在需要注意时闪烁任务栏图标，macOS 上则弹跳程序坞图标。", en = "Allows the client to blink the application icon in the taskbar in Windows, or bounce the application icon in the dock on macOS", ver = "7.2.0" },
	["ExclusiveWindowMode"] = { zh = "防止游戏窗口失去焦点，属于无障碍操作选项。", en = "Accessibility option for preventing the game window from losing focus", ver = "11.0.0" },
	["ForceGenerateSlug"] = { zh = "让所有已加载字体在实际使用前生成 .slug 文件，不再延迟生成。", en = "Generate .slug files for all loaded fonts before they are actually used rather than deferred load.", ver = "10.0.0" },
	["ForceResolutionDefaultToMaxSize"] = { zh = "让默认分辨率采用设备支持的最大尺寸，而不是自动检测的尺寸。", en = "Force default resolution to the maximum supported size rather than the auto-detected size", ver = "9.0.1" },
	["FrameBufferCacheForceNoHeaps"] = { zh = "停用纹理堆并改走备用渲染路径，主要用于兼容性排查。", en = "Disable use of texture heaps and force the fallback path", ver = "9.1.5" },
	["GamePadCameraLookMaxPitch"] = { zh = "限制手柄视角摇杆可调整的镜头俯仰角度上限。", en = "Max pitch 'Look' stick can adjust camera angle", ver = "9.1.5" },
	["GamePadCameraLookMaxYaw"] = { zh = "限制手柄视角摇杆可调整的镜头水平转向角度上限。", en = "Max yaw 'Look' stick can adjust camera angle", ver = "9.1.5" },
	["GamePadCursorAutoDisableJump"] = { zh = "角色跳跃时自动退出手柄光标控制，恢复常规手柄操作。", en = "GamePad cursor control will auto-disable when you jump", ver = "9.0.1" },
	["GamePadCursorAutoDisableSticks"] = { zh = "决定哪些摇杆输入会自动退出手柄光标控制模式。", en = "GamePad cursor control will auto-disable on stick input (0=none, 1=movement, 2=movement+cursor)", ver = "9.0.1" },
	["GamePadCursorCenteredEmulation"] = { zh = "手柄移动时光标居中，并允许手柄同时模拟鼠标点击。", en = "When cursor is centered for GamePad movement, also emulate mouse clicks", ver = "9.0.1" },
	["GamePadCursorCentering"] = { zh = "使用手柄时把光标固定到屏幕中央，便于控制角色移动。", en = "When using GamePad, center the cursor", ver = "9.0.1" },
	["GamePadCursorLeftClick"] = { zh = "指定手柄控制光标时，哪个按键模拟鼠标左键。", en = "GamePad button that should emulate mouse Left Click while controlling the mouse cursor", ver = "9.0.1" },
	["GamePadCursorOnLogin"] = { zh = "在登录与角色选择界面启用手柄光标控制。", en = "Enable GamePad cursor control on login and character screens", ver = "9.0.1" },
	["GamePadCursorPushCamera"] = { zh = "调整手柄光标碰到窗口边缘时推动镜头转向的速度。", en = "Rate for GamePad controlled cursor to push/turn camera when at edge of window", ver = "9.1.0" },
	["GamePadCursorRightClick"] = { zh = "指定手柄控制光标时，哪个按键模拟鼠标右键。", en = "GamePad button that should emulate mouse Right Click while controlling the mouse cursor", ver = "9.0.1" },
	["GamePadCursorSpeedAccel"] = { zh = "调整手柄光标持续移动时每秒增加的速度。", en = "Acceleration of GamePad cursor per second as it continues to move", ver = "9.0.1" },
	["GamePadCursorSpeedMax"] = { zh = "限制手柄光标在界面中移动时能达到的最高速度。", en = "Top speed of GamePad cursor movement", ver = "9.0.1" },
	["GamePadCursorSpeedStart"] = { zh = "调整手柄光标刚开始移动时的初始速度。", en = "Speed of GamePad cursor when it starts moving", ver = "9.0.1" },
	["GamePadEmulateTapWindowMs"] = { zh = "设定手柄模拟 Ctrl、Alt、Shift 时判定短按的时限。", en = "GamePad buttons emulating Ctrl/Alt/Shift will be 'tapped' if released withing this time in MS", ver = "9.2.5" },
	["GamePadFaceMovementMaxAngle"] = { zh = "决定角色移动方向偏离镜头多大时，角色会朝移动方向转身。", en = "Max movement to camera angle to face movement direction instead of camera direction. 0 = always, 180 = never (115 allows using strafe with quick turn around)", ver = "9.1.5" },
	["GamePadFactionColor"] = { zh = "让手柄 LED 灯显示当前角色所属阵营的代表颜色。", en = "Enable setting GamePad's led color to match current faction", ver = "9.2.0" },
	["GamePadOverlapMouseMs"] = { zh = "设定手柄与鼠标混用后，切回单一输入方式的等待时间。", en = "Duration after gamepad+mouse input to switch to just one or the other.", ver = "10.0.0" },
	["GamePadSingleActiveID"] = { zh = "指定唯一生效的手柄设备，设为零时合并所有手柄输入。", en = "ID of single GamePad device to use. 0 = Use all devices' combined input", ver = "9.0.1" },
	["GamePadStickAxisButtons"] = { zh = "把手柄摇杆的上下左右方向识别为可绑定的虚拟按键。", en = "Enables virtual buttons for the GamePad stick cardinal directions", ver = "9.0.5" },
	["GamePadTankTurnSpeed"] = { zh = "让角色按手柄移动方向像坦克一样原地转向，并控制转速。", en = "If non-zero, character turns like a tank from GamePad movement", ver = "9.0.1" },
	["GamePadTouchCursorEnable"] = { zh = "允许使用手柄触控板移动和控制界面光标。", en = "Enable cursor control with GamePad's touch pad", ver = "9.1.5" },
	["GamePadTurnWithCamera"] = { zh = "镜头朝向改变时让角色同步转身，可限定只在战斗中生效。", en = "Turn character to match when camera facing is changed (1=in-combat, 2=always)", ver = "9.1.0" },
	["Gamma"] = { zh = "调整画面 Gamma 校正，影响整体中间亮度与暗部观感。", en = "Gamma correction. Range: [0.3 - 2.8]", ver = "1.0.0" },
	["GxAFRDevicesCount"] = { zh = "强制指定 AFR 交替帧渲染使用的图形设备数量。", en = "Force to set number of AFR devices", ver = "5.x" },
	["GxAdapter"] = { zh = "指定游戏使用的 GPU，留空时由客户端自动选择。", en = "Set which GPU to use. See GxListGPUs for valid names (empty string to let client choose)", ver = "6.0.2" },
	["GxAllowCachelessShaderMode"] = { zh = "按需从硬盘读取 shader 以节省内存，首次显示物体可能稍慢。", en = "CPU memory saving mode, if supported by backend. When enabled, shaders are fetched from disk as needed instead of being kept resident. This mode may slightly increase the time objects take to appear the first time they are encountered. Computers without solid state drives may want to disable this feature", ver = "10.0.0" },
	["GxApi"] = { zh = "选择游戏使用的图形 API，影响渲染方式与硬件兼容性。", en = "graphics api", ver = "1.0.0" },
	["GxCompatAllowSM6"] = { zh = "控制 DX12 是否使用 Shader Model 6 着色器，关闭后改用版本 5。", en = "When disabled, DX12 will use Shader Model 5 shaders instead of Shader Model 6", ver = "11.1.7" },
	["GxCompatAsyncComputeQueue"] = { zh = "允许部分计算任务在独立 GPU 工作队列中运行。", en = "Allows some compute work to run on a different GPU work queue", ver = "11.2.5" },
	["GxCompatAsyncShaderCompilation"] = { zh = "允许异步加载并编译 shader，关闭后画面可能短暂卡顿。", en = "Allows async resource shader loading. Disabling this may cause hitching", ver = "11.1.7" },
	["GxCompatCommandListMultiThreading"] = { zh = "允许多线程提交渲染命令，关闭会明显降低帧率。", en = "Allow multi-threaded rendering. Disabling this will significantly reduce framerate", ver = "11.0.0" },
	["GxCompatCopyQueue"] = { zh = "允许 GPU 上传任务在独立的复制工作队列中运行。", en = "Allows GPU upload work to run on a different GPU work queue", ver = "11.2.5" },
	["GxCompatOptionalGpuFeatures"] = { zh = "让引擎仅按最低 GPU 功能集运行，用于检查高级特性兼容性。", en = "When disabled, makes the engine act as if the GPU only supports the minimum supported feature set", ver = "11.0.0" },
	["GxCompatWorkSubmitOptimizations"] = { zh = "允许次要线程提交 GPU 任务，让其他 CPU 线程继续处理下一帧。", en = "Allows GPU work submission on a secondary thread while the rest of the CPU threads continue on to the next frame", ver = "11.0.0" },
	["GxFullscreenResolution"] = { zh = "设置全屏模式使用的画面分辨率，影响清晰度与渲染负担。", en = "resolution", ver = "7.0.3" },
	["GxMaxFrameLatency"] = { zh = "限制 CPU 最多能比 GPU 提前准备多少帧，影响输入延迟。", en = "maximum number of frames ahead of GPU the CPU can be", ver = "6.2.0" },
	["GxMaximize"] = { zh = "切换游戏使用全屏或窗口显示，改变窗口占用方式。", en = "toggle fullscreen/window", ver = "1.x" },
	["GxMonitor"] = { zh = "指定游戏画面显示在哪台显示器上，零代表主显示器。", en = "Monitor index. 0 means use the primary monitor", ver = "4.x" },
	["GxNewResolution"] = { zh = "记录即将应用的新分辨率，变更后画面尺寸会随之调整。", en = "resolution to be set", ver = "7.0.3" },
	["GxPrismEnabled"] = { zh = "控制 Prism 渲染后端，分为停用、默认和实验模式。", en = "0: Prism backends Disabled. 1: Default Prism backends Enabled. 2: Experimental Prism backends Enabled.", ver = "9.0.1" },
	["GxSlowShaderWarnThreshold"] = { zh = "shader 编译超过设定毫秒数时弹窗提示耗时过长。", en = "Max time (in milliseconds) the shader compile can take before warning via a popup message", ver = "10.2.6" },
	["GxWindowedResolution"] = { zh = "设置窗口模式下的画面分辨率，直接改变游戏窗口尺寸。", en = "windowed resolution", ver = "7.0.3" },
	["ImpactModelCollisionMelee"] = { zh = "让近战命中特效检测模型碰撞，使效果落在接触位置。", en = "Enable model collision checks for melee impact effects", ver = "8.0.1" },
	["ImpactModelCollisionMissile"] = { zh = "让飞弹命中特效检测模型碰撞，使效果落在接触位置。", en = "Enable model collision checks for missile impact effects", ver = "8.0.1" },
	["ImpactModelCollisionRanged"] = { zh = "让远程攻击特效检测模型碰撞，使效果落在接触位置。", en = "Enable model collision checks for ranged attack impact effects", ver = "8.0.1" },
	["InvalidateDeactivatedHandles"] = { zh = "用途:停用实体后让 WowCS Handle 失效(社区文档描述,具体行为未验证)", en = "Turn on to treat WowCS Handles as invalid if referring to a deactivated entity", ver = "11.2.7" },
	["KioskCanSessionExpire"] = { zh = "决定 Kiosk 游玩会话是否会过期，过期后将进入结束流程。", en = "Determines if a Kiosk session can expire. 0: No, 1: Yes (default).", ver = "9.0.1" },
	["KioskCharacterTemplateSet"] = { zh = "指定 Kiosk 创建角色时采用的角色模板集合 ID。", en = "Character template set ID to select at character creation. Defaults to 0.", ver = "9.0.1" },
	["KioskLobbyKickSeconds"] = { zh = "设定 Kiosk 会话过期后，玩家被送回大厅前等待的秒数。", en = "Seconds until an expired session kicks the player back to the lobby. Defaults to 30 seconds.", ver = "9.0.1" },
	["LowLatencyMinInterval"] = { zh = "设定低延迟系统的最短帧时间，也可跟随显示器刷新率。", en = "Min frame time (in microseconds) for Low Latency systems. Pass -1 to use monitor's refresh rate.", ver = "11.2.5" },
	["LowLatencyMode"] = { zh = "选择低延迟技术模式，包括内置、Reflex、Reflex+Boost 与 XeLL。", en = "0=None, 1=BuiltIn, 2=Reflex, 3=Reflex+Boost, 4=XeLL", ver = "10.0.0" },
	["M2ForceAdditiveParticleSort"] = { zh = "强制所有粒子按 additive 混合方式排序，改变透明特效叠放。", en = "force all particles to sort as though they were additive", ver = "2.x" },
	["M2UseInstancing"] = { zh = "让相同模型使用硬件实例化批量渲染，影响场景绘制方式。", en = "use hardware instancing", ver = "6.0.2" },
	["M2UseThreads"] = { zh = "让模型动画使用多线程处理，改变 CPU 动画计算方式。", en = "multithread model animations", ver = "1.0.0" },
	["MSAAAlphaTest"] = { zh = "让带透明裁切的模型表面也应用 MSAA，改善锯齿边缘。", en = "Enable MSAA for alpha-tested geometry", ver = "6.1.0" },
	["MSAAQuality"] = { zh = "调整 MSAA 多重采样抗锯齿质量，影响边缘平滑度与性能。", en = "Multisampling AA quality", ver = "6.1.0" },
	["MaxCharacterComponentLoadStartsPerFrame"] = { zh = "限制每帧开始合成的角色部件纹理数量，范围一至八个。", en = "Maximum number of character component textures to composit per frame - range 1-8", ver = "11.0.0" },
	["MaxObservedPetBattles"] = { zh = "限制客户端同时观察和处理的宠物对战数量上限。", en = "Maximum number of observed pet battles", ver = "5.x" },
	["MouseHiddenInRelativeMode"] = { zh = "控制相对鼠标模式下是否隐藏指针，关闭可绕过少数异常。", en = "Disabling may work around issues in relative mode in some rare cases", ver = "11.0.0" },
	["NonEmitterCombatRange"] = { zh = "角色离开战斗后，超出此距离便停止肩部和武器发光特效。", en = "Range to stop shoulder/weapon emissions outside combat", ver = "6.0.2" },
	["NotchedDisplayMode"] = { zh = "调整刘海屏避让方式，可下移界面或下移整个画面。", en = "Do nothing = 0. Shift UI down = 1. Shift everything down = 2.", ver = "9.2.0" },
	["ObjectSelectionCircle"] = { zh = "显示或隐藏所选角色或宠物脚下的选择圆圈。", en = "This CVar turns the circle under a selected person/pet on and off.", ver = "1.0.0" },
	["Outline"] = { zh = "控制物体轮廓线的显示模式，影响目标边缘的高亮效果。", en = "Outline Mode", ver = "1.0.0" },
	["OutlineEngineMode"] = { zh = "选择引擎使用 OutlineBuffer 绘制轮廓线的工作模式。", en = "Mode for the OutlineBuffer for the engine", ver = "6.0.2" },
	["PreemptiveCastEnable"] = { zh = "按法术释放时机提前触发施法视觉效果，使动画更早出现。", en = "Enable preemptive triggering of cast visuals based on spell release timing", ver = "7.3.0" },
	["PreventOsIdleSleep"] = { zh = "游戏运行时阻止操作系统因长时间无操作而自动休眠。", en = "Enable this to prevent the computer from idle sleeping while the game is running", ver = "8.3.0" },
	["PushToTalkSound"] = { zh = "语音录制开始和结束时播放提示音，便于确认按键说话状态。", en = "Play a sound when voice recording activates and deactivates", ver = "3.x" },
	["RAIDDepthBasedOpacity"] = { zh = "控制团队副本画面的柔化边缘效果，让交界处过渡更平滑。", en = "Raid Enable/Disable Soft Edge Effect", ver = "6.1.0" },
	["RAIDOutlineEngineMode"] = { zh = "选择团队副本画面中 OutlineBuffer 的轮廓绘制模式。", en = "Mode for the OutlineBuffer", ver = "6.1.0" },
	["RAIDParticulatesEnabled"] = { zh = "控制团队副本中的细小粒子效果是否显示。", en = "Enabling particulates (0-1)", ver = "9.0.1" },
	["RAIDSSAO"] = { zh = "控制团队副本中的屏幕空间环境光遮蔽，影响角落阴影层次。", en = "Raid Screen-Space Ambient Occlusion", ver = "6.0.2" },
	["RAIDTerrainLodDiv"] = { zh = "调整团队副本地形的细节层级换算比例，影响远景精细度。", en = "Raid Terrain lod divisor", ver = "9.0.1" },
	["RAIDVolumeFog"] = { zh = "控制团队副本中的体积雾效果，影响雾气的空间层次。", en = "Volume Fog", ver = "9.1.0" },
	["RAIDVolumeFogLevel"] = { zh = "调整团队副本体积雾的质量等级，影响雾气细节与性能。", en = "Volume Fog Level (0-3)", ver = "8.0.1" },
	["RAIDWaterDetail"] = { zh = "调整团队副本水面细节等级，影响波纹与反射表现。", en = "Raid Water surface detail", ver = "6.0.2" },
	["RAIDclusteredShading"] = { zh = "允许团队副本中的透明物体接受前向光照效果。", en = "Allow forward transparent lighting", ver = "11.0.0" },
	["RAIDcomponentTextureLevel"] = { zh = "调整团队副本角色部件纹理细节，零代表完整细节。", en = "Level of detail for character component textures. 0 means full detail.", ver = "6.0.2" },
	["RAIDdoodadLodScale"] = { zh = "调整团队副本场景摆件的细节层级比例，影响远近模型精度。", en = "Raid doodad level of detail scale", ver = "9.0.1" },
	["RAIDentityLodDist"] = { zh = "调整团队副本实体切换细节层级的距离。", en = "Raid Entity level of detail distance", ver = "8.0.1" },
	["RAIDentityShadowFadeScale"] = { zh = "调整团队副本实体阴影随距离淡出的速度比例。", en = "Raid Entity shadow fade scale", ver = "8.0.1" },
	["RAIDgraphicsQuality"] = { zh = "保存团队副本图形质量档位，供整体画质选项调用。", en = "save for Raid Graphics Quality Selection", ver = "6.0.2" },
	["RAIDgroundEffectDensity"] = { zh = "调整团队副本地面装饰效果的密度，影响草木等细节数量。", en = "Raid Ground effect density", ver = "6.0.2" },
	["RAIDgroundEffectDist"] = { zh = "调整团队副本地面装饰效果的最远显示距离。", en = "Raid Ground effect dist", ver = "6.0.2" },
	["RAIDgroundEffectFade"] = { zh = "调整团队副本地面装饰效果开始淡出的距离。", en = "Raid Ground effect fade", ver = "6.0.2" },
	["RAIDhorizonClip"] = { zh = "设定团队副本地平线的最远裁切距离，超出部分不再绘制。", en = "Raid Horizon end distance", ver = "9.0.1" },
	["RAIDhorizonStart"] = { zh = "设定团队副本地平线效果开始出现或过渡的距离。", en = "Raid Horizon start distance", ver = "7.0.3" },
	["RAIDlodObjectCullDist"] = { zh = "设定团队副本低细节物体被剔除的最小距离。", en = "Lod object culling dist minimum", ver = "7.0.3" },
	["RAIDlodObjectCullSize"] = { zh = "设定团队副本低细节物体被剔除时参考的尺寸门槛。", en = "Lod object culling size", ver = "7.0.3" },
	["RAIDlodObjectFadeScale"] = { zh = "调整团队副本低细节物体随距离淡出的比例。", en = "Lod object fade scale", ver = "7.2.0" },
	["RAIDlodObjectMinSize"] = { zh = "控制团队副本中物体启用低细节模型的尺寸门槛，影响远景精细度。", en = "Lod object min size", ver = "7.0.3" },
	["RAIDparticleMTDensity"] = { zh = "控制团队副本中 Multi-Tex 粒子密度，数值变化会影响特效丰富程度。", en = "Multi-Tex particle density", ver = "6.1.0" },
	["RAIDprojectedTextures"] = { zh = "控制团队副本中的投射纹理显示，例如地面法术效果和部分阴影。", en = "Projected Textures", ver = "6.0.2" },
	["RAIDreflectionMode"] = { zh = "控制团队副本的水面与场景反射质量，档位越高反射通常越细致。", en = "Reflection mode", ver = "6.0.2" },
	["RAIDrefraction"] = { zh = "控制团队副本中的折射效果，影响水面或透明材质造成的光线扭曲。", en = "Refraction", ver = "6.0.2" },
	["RAIDrippleDetail"] = { zh = "控制团队副本中水面波纹的细节等级，影响水体动态效果。", en = "Ripple surface detail", ver = "6.0.2" },
